'use client';

import { usePathname } from 'next/navigation';
import Link from 'next/link';
import {
  LayoutDashboard,
  Table2,
  Users,
  Home,
  Sun,
  Moon,
} from 'lucide-react';
import { useState } from 'react';

const NAV = [
  { href: '/', label: 'Accueil', icon: Home },
  { href: '/workspace', label: 'Espace de travail', icon: LayoutDashboard },
  { href: '/results', label: 'Résultats', icon: Table2 },
  { href: '/collaboration', label: 'Collaboration', icon: Users },
];

export default function Sidebar() {
  const path = usePathname();
  const [dark, setDark] = useState(false);

  function toggleDark() {
    setDark(!dark);
    document.documentElement.classList.toggle('dark');
  }

  return (
    <aside className="w-60 h-screen fixed left-0 top-0 z-40 border-r border-gray-200 dark:border-gray-800 bg-white dark:bg-gray-950 flex flex-col">
      {/* ── Logo ──────────────────────────────────────────── */}
      <div className="flex items-center gap-2.5 px-5 py-5">
        <div className="w-9 h-9 rounded-xl bg-gradient-to-br from-teal-500 to-emerald-600 text-white flex items-center justify-center font-bold text-sm shadow-md shadow-teal-500/20">
          T
        </div>
        <span className="font-semibold text-gray-900 dark:text-white text-lg tracking-tight">
          TIMEASE
        </span>
      </div>

      {/* ── Navigation ────────────────────────────────────── */}
      <nav className="flex-1 flex flex-col gap-0.5 px-3 mt-2">
        {NAV.map((n) => {
          const active =
            path === n.href || (n.href !== '/' && path.startsWith(n.href));
          return (
            <Link
              key={n.href}
              href={n.href}
              className={`flex items-center gap-2.5 px-3 py-2.5 rounded-lg text-[13.5px] transition-all duration-150 ${
                active
                  ? 'bg-teal-50 text-teal-700 dark:bg-teal-900/30 dark:text-teal-300 font-medium shadow-sm'
                  : 'text-gray-500 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-900 hover:text-gray-700 dark:hover:text-gray-300'
              }`}
            >
              <n.icon size={18} strokeWidth={active ? 2 : 1.5} />
              {n.label}
            </Link>
          );
        })}
      </nav>

      {/* ── Dark mode toggle ──────────────────────────────── */}
      <div className="px-3 pb-4">
        <button
          onClick={toggleDark}
          className="flex w-full items-center gap-2 px-3 py-2.5 text-gray-400 dark:text-gray-500 text-[13px] hover:bg-gray-50 dark:hover:bg-gray-900 rounded-lg transition-colors"
        >
          {dark ? <Sun size={16} /> : <Moon size={16} />}
          {dark ? 'Mode clair' : 'Mode sombre'}
        </button>
      </div>
    </aside>
  );
}
